const { execSync } = require('child_process');
const folderPath = '/home/paolice-mylze/capture pindou/1';

try {
  const stdout = execSync(
    `find "${folderPath}" -maxdepth 1 -type f \( -iname '*.jpg' -o -iname '*.jpeg' -o -iname '*.png' \) | grep -i 'capture' | grep -v '/traites/' | sort`,
    { encoding: 'utf8', timeout: 10000 }
  ).trim();
  return [{ json: { stdout, stderr: '', code: 0 } }];
} catch (err) {
  // execSync throws if command returns non-zero (e.g. grep finds nothing)
  const stdout = (err.stdout || '').trim();
  return [{ json: { stdout, stderr: err.stderr || '', code: err.status || 1 } }];
}

// Convertir la liste de fichiers en items n8n
const output = $input.first().json.stdout || '';
const files = output.split('\n').filter(f => f.trim() !== '');

if (files.length === 0) {
  console.log('Aucun screenshot à traiter.');
  return [];
}

console.log(`📋 ${files.length} screenshot(s) trouvé(s)`);

return files.map(filePath => ({
  json: {
    screenshot_path: filePath.trim(),
    screenshot_name: filePath.trim().split('/').pop(),
    // Préfixe pour retrouver les images propres (ex: 'capture' → chercher 'IMG_*' dans le même dossier)
    folder: filePath.trim().split('/').slice(0, -1).join('/')
  }
}));

// Parser la réponse JSON de l'IA
const aiResponse = $input.first().json;
const content = aiResponse.choices?.[0]?.message?.content || '{}';

let productData;
try {
  // Nettoyer la réponse (parfois l'IA ajoute des backticks)
  const cleaned = content.replace(/```json?\n?/g, '').replace(/```/g, '').trim();
  productData = JSON.parse(cleaned);
} catch (e) {
  console.error('Erreur parsing JSON IA:', e.message);
  console.error('Contenu IA brut:', content);
  productData = {
    name_fr: 'Produit importé',
    price_cny: null,
    description_fr: 'Description à compléter',
    weight_kg: 0.5,
    category_fr: 'autres',
    color: null,
    quantity: 1,
    brand: null,
    _parse_error: e.message
  };
}

// Récupérer les données du screenshot
const screenshotData = $('🔍 Parser Liste Fichiers').item.json;

return [{
  json: {
    ...productData,
    screenshot_path: screenshotData.screenshot_path,
    screenshot_name: screenshotData.screenshot_name,
    folder: screenshotData.folder,
    ai_raw_response: content
  }
}];

// Charger la config fret depuis le fichier JSON
// (valeurs encodées ici pour éviter la dépendance fichier dans n8n)
const freightConfig = {
  aerien: { prix_par_kg: 25, delai_jours: 10 },
  maritime: { prix_par_m3: 750, delai_jours: 60 },
  CNY_to_USD: 0.138,
  marge: 0.30,
  seuil_maritime_kg: 10
};

const item = $input.first().json;
const priceCny = parseFloat(item.price_cny) || 0;
const weightKg = parseFloat(item.weight_kg) || 0.5;

// 1. Conversion CNY → USD
const priceUsd = priceCny * freightConfig.CNY_to_USD;

// 2. Choix mode fret
const freightMode = weightKg >= freightConfig.seuil_maritime_kg ? 'maritime' : 'aerien';

let freightCost = 0;
let deliveryTime = '';

if (freightMode === 'aerien') {
  const effectiveWeight = Math.max(weightKg, 0.1);
  freightCost = effectiveWeight * freightConfig.aerien.prix_par_kg;
  deliveryTime = `${freightConfig.aerien.delai_jours} jours (fret aérien)`;
} else {
  // Maritime : convertir kg en m³ (densité moyenne colis = 200kg/m³)
  const volumeM3 = Math.max(weightKg / 200, 0.01);
  freightCost = volumeM3 * freightConfig.maritime.prix_par_m3;
  deliveryTime = `${freightConfig.maritime.delai_jours} jours (fret maritime)`;
}

// 3. Prix final avec marge
const basePrice = priceUsd + freightCost;
const finalPrice = basePrice * (1 + freightConfig.marge);

console.log(`💰 Calcul fret: CNY${priceCny} → $${priceUsd.toFixed(2)} + fret $${freightCost.toFixed(2)} + marge = $${finalPrice.toFixed(2)}`);

return [{
  json: {
    ...item,
    freight_mode: freightMode,
    freight_cost_usd: parseFloat(freightCost.toFixed(2)),
    price_source_usd: parseFloat(priceUsd.toFixed(2)),
    price_final_usd: parseFloat(finalPrice.toFixed(2)),
    delivery_time: deliveryTime,
    calculation_detail: {
      cny: priceCny,
      usd_source: parseFloat(priceUsd.toFixed(2)),
      freight: parseFloat(freightCost.toFixed(2)),
      marge_30pct: parseFloat((basePrice * 0.30).toFixed(2)),
      total: parseFloat(finalPrice.toFixed(2))
    }
  }
}];

const { execSync } = require('child_process');
const folder = $input.first().json.folder || '';

try {
  const stdout = execSync(
    `find "${folder}" -maxdepth 1 -type f \( -iname 'IMG_*.jpg' -o -iname 'IMG_*.jpeg' -o -iname 'IMG_*.png' -o -iname 'IMG_*.JPG' -o -iname 'IMG_*.JPEG' \) | grep -v '/traites/' | sort | head -8`,
    { encoding: 'utf8', timeout: 10000 }
  ).trim();
  return [{ json: { stdout, stderr: '', code: 0 } }];
} catch (err) {
  const stdout = (err.stdout || '').trim();
  return [{ json: { stdout, stderr: err.stderr || '', code: err.status || 1 } }];
}

// Convertir liste d'images en tableau
const output = $input.first().json.stdout || '';
const imagePaths = output.split('\n').filter(f => f.trim() !== '');

if (imagePaths.length === 0) {
  // Si aucune image propre trouvée, utiliser le screenshot lui-même
  const screenshotPath = $('📊 Parser Données IA').item.json.screenshot_path;
  console.warn('⚠️ Aucune image propre trouvée, utilisation du screenshot:', screenshotPath);
  return [{
    json: {
      ...$('🚢 Calcul Frais Fret').item.json,
      image_paths: [screenshotPath],
      images_count: 1,
      images_source: 'screenshot_fallback'
    }
  }];
}

console.log(`🖼️ ${imagePaths.length} image(s) propre(s) trouvée(s)`);

return [{
  json: {
    ...$('🚢 Calcul Frais Fret').item.json,
    image_paths: imagePaths.map(p => p.trim()),
    images_count: imagePaths.length,
    images_source: 'product_photos'
  }
}];

// Upload chaque image vers Cloudinary et collecter les URLs
// Note: Cette étape utilise l'API Cloudinary directement
// Prérequis: credentials Cloudinary configurés dans n8n

const item = $input.first().json;
const imagePaths = item.image_paths || [];

// Pour l'upload on va passer les chemins à une boucle
// Dans n8n, on retourne les chemins pour le node HTTP suivant
return [{
  json: {
    ...item,
    images_to_upload: imagePaths,
    cloudinary_cloud_name: 'dbfpnxjmm',
    cloudinary_upload_preset: 'oli_app'
  }
}];

// Upload des images vers Cloudinary via API REST
// On simule l'upload en lisant les fichiers et les envoyant
// Cette version construit les URLs d'upload pour chaque image

const item = $input.first().json;
const fs = require('fs');
const https = require('https');
const FormData = require('form-data');
const path = require('path');

const cloudName = item.cloudinary_cloud_name;
const uploadUrl = `https://api.cloudinary.com/v1_1/${cloudName}/image/upload`;

const uploadedUrls = [];

for (const imagePath of item.images_to_upload) {
  try {
    // Lire le fichier en base64
    const imageBuffer = fs.readFileSync(imagePath);
    const base64Image = imageBuffer.toString('base64');
    const mimeType = imagePath.toLowerCase().endsWith('.png') ? 'image/png' : 'image/jpeg';
    const dataUri = `data:${mimeType};base64,${base64Image}`;

    // Upload via fetch (disponible dans Node 18+)
    const response = await fetch(uploadUrl, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        file: dataUri,
        upload_preset: 'oli_n8n_import',
        folder: 'oli_app',
        tags: ['n8n_import', 'chinese_sourcing']
      })
    });

    const result = await response.json();
    if (result.secure_url) {
      uploadedUrls.push(result.secure_url);
      console.log(`✅ Image uploadée: ${result.secure_url}`);
    } else {
      console.warn(`⚠️ Erreur upload Cloudinary:`, JSON.stringify(result));
    }
  } catch (err) {
    console.error(`❌ Erreur upload image ${imagePath}:`, err.message);
  }
}

if (uploadedUrls.length === 0) {
  throw new Error('Aucune image uploadée avec succès vers Cloudinary');
}

return [{
  json: {
    ...item,
    cloudinary_urls: uploadedUrls,
    images_uploaded: uploadedUrls.length
  }
}];

const { execSync } = require('child_process');
const screenshotPath = $('📋 Parser Images').item.json.screenshot_path || '';
const destFolder = '/home/paolice-mylze/capture pindou/1/traites';

if (!screenshotPath) {
  throw new Error('Chemin screenshot introuvable pour archivage');
}

try {
  execSync(`mkdir -p "${destFolder}"`, { encoding: 'utf8' });
  execSync(`mv "${screenshotPath}" "${destFolder}/"`, { encoding: 'utf8' });
  console.log(`✅ Screenshot archivé: ${screenshotPath} → ${destFolder}/`);
  return [{ json: { moved: true, source: screenshotPath, destination: destFolder } }];
} catch (err) {
  console.error('❌ Erreur archivage screenshot:', err.message);
  // Ne pas bloquer le workflow si le déplacement échoue
  return [{ json: { moved: false, error: err.message, source: screenshotPath } }];
}

// Rapport de succès pour ce produit
const oliResponse = $('📡 Publier sur Oli').item.json;
const calcData = $('🚢 Calcul Frais Fret').item.json;

console.log('\n✅ ═══════════════════════════════════════');
console.log(`✅ PRODUIT PUBLIÉ: "${oliResponse.name}"`);
console.log(`   🆔 ID Oli: ${oliResponse.productId}`);
console.log(`   💰 Prix: $${oliResponse.price} (source: ¥${calcData.price_cny} CNY)`);
console.log(`   🚚 Fret ${oliResponse.freight_mode}: $${oliResponse.delivery_price}`);
console.log(`   🖼️ Images: ${oliResponse.images_count}`);
console.log(`   📁 Source: ${oliResponse.source_file}`);
console.log('✅ ═══════════════════════════════════════\n');

return [{
  json: {
    status: 'success',
    product_id: oliResponse.productId,
    product_name: oliResponse.name,
    price_usd: oliResponse.price,
    price_cny: calcData.price_cny,
    freight_usd: oliResponse.delivery_price,
    freight_mode: oliResponse.freight_mode,
    images_count: oliResponse.images_count,
    source_file: oliResponse.source_file,
    timestamp: new Date().toISOString()
  }
}];
